import React, { useEffect, useState } from 'react';
import Column from '../Column';
import * as C from './style';

function Main({ pedidos }) {
    
    if(pedidos.length > 0){
        var pedidos1 = pedidos.filter( e => e.horaEntrega === "19:30")
        var pedidos2 = pedidos.filter( e => e.horaEntrega === "20:00")
        var pedidos3 = pedidos.filter( e => e.horaEntrega === "20:30")
        var pedidos4 = pedidos.filter( e => e.horaEntrega === "21:00")
        var pedidos5 = pedidos.filter( e => e.horaEntrega === "21:30")
    }
    
    console.log("Oi, cheguei até aqui");
    return (
        <C.Container>
            {pedidos1.length > 1 && (<Column title='19:30' pedidos={pedidos1}/>)}
            {pedidos2.length > 1 && (<Column title='20:00' pedidos={pedidos2}/>)}
            {pedidos3.length > 1 && (<Column title='20:30' pedidos={pedidos3}/>)}
            {pedidos4.length > 1 && (<Column title='21:00' pedidos={pedidos4}/>)}
            {pedidos5.length > 1 && (<Column title='21:30' pedidos={pedidos5}/>)}
        </C.Container>
    )
}

export default Main
